/* TODO: [변환 불가] QIPA302 SQLIO 소스 미확보 */
/* FUBcEmployee.getPafiarEmpInfo() 공통 유틸 호출로 대체 검토 필요 */
/* 임시: n-KESA FUBcEmployee 공통 유틸 사용 권고 */
SELECT EMP_HANGL_FNAME
     , BELNG_BRNCD
  FROM BANKDB.THKJIHR01
 WHERE GROUP_CO_CD = #groupCoCd:VARCHAR#
   AND EMP_NO      = #userEmpid:VARCHAR#
